import logging
from logging.handlers import RotatingFileHandler

# Configure file handlers to write logs to /var/log/application/
file_handler = RotatingFileHandler('/var/log/application', maxBytes=1024 * 1024, backupCount=5)

# Set up log rotation and formatting
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
file_handler.setFormatter(formatter)
logging.basicConfig(handlers=[file_handler], level=logging.INFO)